INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic) VALUES
('56f0be04-0f11-5069-ab92-07d25eda9ee3', 'd99f5952-91d8-41d5-8a1c-267609e39a20', 'The trip to the museum takes ___ thirty minutes.', '去博物館的行程大約需要三十分鐘。', 'about', 'exactly', 'highly', 'suddenly', '表示數量或時間的近似值 (大約)', 'about + [數字] → 大約的數量'),
('1c79c445-9a96-532b-908d-3824d5f38f67', 'bdf62229-5b97-4ca6-b357-8e0d6aac7c03', 'I will give ___ the instructions so that you can start the task immediately.', '我會給你指示，這樣你就能立即開始這項任務。', 'you', 'him', 'her', 'them', 'you 為代名詞，在此作為受格使用。', 'you 就是你，對著對方說話時必備。'),
('af3590fd-778a-55e3-b642-5a3a3a8fef8f', '1d86e27e-0866-4c5e-8277-4bc91cc8ab5e', 'Is ___ the reason why you were so angry this morning?', '那就是你今天早上為什麼這麼生氣的原因嗎？', 'that', 'what', 'which', 'who', '代名詞 (pron.)，用來指代前面提到或已知的事物。', 'That (那件事) → 指代已知的事。');
